module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);

reg [15:0] p_reg, acc_reg;
reg [6:0] temp_reg;
wire [7:0] a, b;
assign a = mul_a;
assign b = mul_b;

wire [15:0] p;
wire [6:0] temp;
wire [15:0] &p_group;
wire [6:0] (&p_group) temp_acc;

assign temp = (b[0] & a[0]) + (b[0] & a[1]) + (b[1] & a[0]);
assign p_group[0] = (b[0] & a[0]) + (b[0] & a[1]) + (b[1] & a[0]);
assign temp_acc[0] = (p_reg[0] & acc_reg[15:8]);

genvar i;
generate
    for (i = 0; i < 8; i = i + 1) begin : partial_product_gen
        if (i == 0) begin
            assign temp[0] = (b[0] & a[0]);
            assign p_group[0] = (b[0] & a[1]) + (b[1] & a[0]);
            assign temp_acc[0] = (p_reg[0] & acc_reg[15:8]);
        end else begin
            assign temp[i] = (b[i] & a[0]);
            assign p_group[i] = (b[i] & a[7:1]) + p_group[i-1];
            assign temp_acc[i] = (p_reg[i] & acc_reg[15:8]);
        end
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_reg <= 0;
        acc_reg <= 0;
        temp_reg <= 0;
    end else begin
        p_reg <= p;
        acc_reg <= p_reg;
        temp_reg <= temp;
    end
end

assign mul_en_out = mul_en_in;
assign mul_out = p_reg;

endmodule
